import React, { useContext } from 'react';
import { useState, useEffect } from 'react';
import './App.css';
import AccountMenu from './AccountMenu';
import UserContext from './User';
import Footer from './Footer';

export default function App() {
  const [reservations, setReservations] = useState([]);

  const userId = useContext(UserContext);
  console.log("userId: ", userId)
  const url = 'http://localhost:9000/reservations?userid=' + userId;

  useEffect(() => {
    fetch(url)
      .then((response) => response.json())
      .then((reservations) => {
        console.log(reservations);
        setReservations(reservations);
      })
      .catch((err) => {
        console.log(err.message);
      });
  }, []);


  return (
    <div className="Favourites">
      <script src="https://cdn.jsdelivr.net/npm/bootstrap@5.2.1/dist/js/bootstrap.bundle.min.js"
        integrity="sha384-u1OknCvxWvY5kfmNBILK2hRnQC3Pr17a+RTT6rIHI7NnikvbZlHgTPOOmMi466C8" crossorigin="anonymous">
      </script>

      <header className="main-header mt-auto py-3 bg-light fixed-top">
        <nav className="navbar navbar-expand-lg fixed-top navbar-light bg-light ">
          <a className="navbar-brand" href="/">
            <img src="../img/logo.png" width="10%" className="align-top" />
            <span className="logo text-uppercase font-weight-bold align-bottom">Aptic</span>
          </a>
          <button className="navbar-toggler" type="button" data-bs-toggle="collapse" data-bs-target="#navbar"
            aria-controls="navbar" aria-expanded="false" aria-label="Toggle navigation">
            <span className="navbar-toggler-icon"></span>
          </button>

          <div className="collapse navbar-collapse " id="navbar">

          </div>

          <div>
              <AccountMenu />
          </div>
        </nav>
      </header>

      {/* Reservation Table */}
      <div className="container" style={{marginTop : '5%'}}>
        <div className="row" >
          <div className="col-12">
            <table className="table table-bordered" >
              <thead>
                <tr>
                  <th scope="col">Sr. No.</th>
                  <th scope="col">Title</th>
                  <th scope="col">Location</th>
                  <th scope="col">Checkin Date</th>
                  <th scope="col">Checkout Date</th>
                  <th scope="col">Actions</th>
                </tr>
              </thead>

              <tbody>
                {Object.keys(reservations).map((key) => 
                  <tr>
                    <th scope="row">{key}</th>
                    <td>{reservations[key].title}</td>
                    <td>{reservations[key].location}</td>
                    <td>{reservations[key].checkin}</td>
                    <td>{reservations[key].checkout}</td>
                    <td>
                      { new Date(reservations[key].checkin) - new Date() > 2
                        // ? <button type="button" className="btn btn-primary"><i className="far" />Review</button>
                        ? <button type="button" className="btn btn-danger"><i className="far" />Cancel {console.log(new Date(reservations[key].checkin) - new Date())}</button>
                        : <button type="button" className="btn btn-primary"><i className="far" />Review</button>
                      }
                    </td>
                  </tr>
                )}

              </tbody>
            </table>
          </div>
        </div>
      </div>


      <Footer />

    </div >
  );
}
